module top_module(
    input [7:0] Anti_A,
    input [7:0] B,
    output reg [7:0] Sum,
    output reg [7:0] Diff,
    output reg [7:0] Prod,
    output reg [7:0] Quot
    );always @* begin
        Sum = Anti_A + B;
        Diff = Anti_A - B;
        Prod = Anti_A * B;
        if (B == 0) begin
            Quot = 8'hFF;
        end else begin
            Quot = Anti_A / B;
        end
    end

endmodule
